        assertThat(customList1Item.text).isEqualTo(UiStringText("custom-list-1"))
    }

    @Test
    fun `GIVEN two custom lists WHEN createMenu THEN custom lists shown directly in menu`() {
        val tags = ReaderTagList().apply {
            add(mockFollowingTag()) // item 0
            add(mockDiscoverTag()) // item 1
            add(mockSavedTag()) // item 2
            add(createCustomListTag("custom-list-1")) // item 3
            add(createCustomListTag("custom-list-2")) // item 4
        }

        val menu = helper.createMenu(tags)

        assertThat(menu).contains(MenuElementData.Divider)

        // Should not have a submenu
        val customListsSubmenu = menu.findSubMenu()
        assertThat(customListsSubmenu).isNull()

        // Should have both custom lists directly in the menu
        val customList1Item = menu.findSingleItem { it.id == "3" }!!
        assertThat(customList1Item.text).isEqualTo(UiStringText("custom-list-1"))

        val customList2Item = menu.findSingleItem { it.id == "4" }!!
        assertThat(customList2Item.text).isEqualTo(UiStringText("custom-list-2"))
    }

    @Test
    fun `GIVEN three custom lists WHEN createMenu THEN custom lists shown in submenu`() {
        val tags = ReaderTagList().apply {
            add(mockFollowingTag()) // item 0
            add(mockDiscoverTag()) // item 1
            add(mockSavedTag()) // item 2
            add(createCustomListTag("custom-list-1")) // item 3
            add(createCustomListTag("custom-list-2")) // item 4
            add(createCustomListTag("custom-list-3")) // item 5
        }

        val menu = helper.createMenu(tags)

        assertThat(menu).contains(MenuElementData.Divider)

        // Should have a submenu
        val customListsSubmenu = menu.findSubMenu()!!
        assertThat(customListsSubmenu.text).isEqualTo(UiStringRes(R.string.reader_dropdown_menu_lists))

        // Should have all custom lists in the submenu
        val customList1Item = customListsSubmenu.children.findSingleItem { it.id == "3" }!!
        assertThat(customList1Item.text).isEqualTo(UiStringText("custom-list-1"))

        val customList2Item = customListsSubmenu.children.findSingleItem { it.id == "4" }!!
        assertThat(customList2Item.text).isEqualTo(UiStringText("custom-list-2"))

        val customList3Item = customListsSubmenu.children.findSingleItem { it.id == "5" }!!
        assertThat(customList3Item.text).isEqualTo(UiStringText("custom-list-3"))
    }

